#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)
#define ASSUMED_NR_CLUSTERS 32

__constant float c_clusters[ASSUMED_NR_CLUSTERS*34];

__kernel void invert_mapping(__global float *input,
                             __global float *output,
                             int npoints,
                             int nfeatures)
{
    int point_id = get_global_id(0);
    if(point_id < npoints){
        for(int i=0; i<nfeatures; i++)
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
    }
}

inline float tex1Dfetch(__global const float* arr, int idx)
{
    return arr[idx];
}

// To emulate textures, pass buffers and use tex1Dfetch inline function.

__kernel void kmeansPoint(__global float *features,
                          int nfeatures,
                          int npoints,
                          int nclusters,
                          __global int *membership,
                          __global float *clusters,
                          __global float *block_clusters,
                          __global int *block_deltas)
{
    const int block_dim_x = get_local_size(0);
    const int block_dim_y = 1;
    const int block_id_x = get_group_id(0);
    const int block_id_y = get_group_id(1);
    const int grid_dim_x = get_num_groups(0);

    const unsigned int block_id = grid_dim_x*block_id_y + block_id_x;
    const unsigned int point_id = block_id * block_dim_x * block_dim_y + get_local_id(0);

    int index = -1;

    if (point_id < npoints)
    {
        float min_dist = FLT_MAX;
        for (int i=0; i<nclusters; i++) {
            int cluster_base_index = i*nfeatures;
            float ans=0.0f;

            for (int j=0; j < nfeatures; j++)
            {
                int addr = point_id + j*npoints;
                float diff = tex1Dfetch(features, addr) - c_clusters[cluster_base_index + j];
                ans += diff*diff;
            }
            float dist = ans;

            if (dist < min_dist) {
                min_dist = dist;
                index = i;
            }
        }
    }

#ifdef GPU_DELTA_REDUCTION
    __local int deltas[THREADS_PER_BLOCK];
    if(get_local_id(0) < THREADS_PER_BLOCK) {
        deltas[get_local_id(0)] = 0;
    }
    barrier(CLK_LOCAL_MEM_FENCE);
#endif

    if (point_id < npoints)
    {
#ifdef GPU_DELTA_REDUCTION
        if (membership[point_id] != index) {
            deltas[get_local_id(0)] = 1;
        }
#endif
        membership[point_id] = index;
    }

#ifdef GPU_DELTA_REDUCTION
    barrier(CLK_LOCAL_MEM_FENCE);

    unsigned int threadids_participating = THREADS_PER_BLOCK / 2;
    while(threadids_participating > 1) {
        if(get_local_id(0) < threadids_participating) {
            deltas[get_local_id(0)] += deltas[get_local_id(0) + threadids_participating];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        threadids_participating /= 2;
    }
    if(get_local_id(0) == 0) {
        deltas[0] += deltas[1];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if(get_local_id(0) == 0) {
        block_deltas[block_id_y * grid_dim_x + block_id_x] = deltas[0];
    }
#endif

#ifdef GPU_NEW_CENTER_REDUCTION
    int center_id = get_local_id(0) / nfeatures;
    int dim_id = get_local_id(0) - nfeatures*center_id;

    __local int new_center_ids[THREADS_PER_BLOCK];

    new_center_ids[get_local_id(0)] = index;
    barrier(CLK_LOCAL_MEM_FENCE);

    int new_base_index = (point_id - get_local_id(0))*nfeatures + dim_id;
    float accumulator = 0.f;

    if(get_local_id(0) < nfeatures * nclusters) {
        for(int i = 0; i < THREADS_PER_BLOCK; i++) {
            float val = tex1Dfetch(features, new_base_index + i*nfeatures);
            if(new_center_ids[i] == center_id)
                accumulator += val;
        }
        block_clusters[block_id * nclusters * nfeatures + get_local_id(0)] = accumulator;
    }
#endif
}
